from setuptools import setup, find_packages
import requests

def get_dependencies(url):
    res = requests.get(url)
    if res.status_code == 200:
        return [line.strip() for line in res.text.split("\n")]
    else:
        print("Failed to fetch dependencies from url {}".format(url))
        exit(-1)

